import React from "react";
import { Button } from "@/components/ui/button";
import { TrashIcon } from "lucide-react";
import type { ArrayElementWrapperProps } from "@dual-autoform/react";

export const ArrayElementWrapper: React.FC<ArrayElementWrapperProps> = ({
  children,
  onRemove,
}) => {
  return (
    <div className="relative border p-4 rounded-md mt-2">
      <Button
        onClick={onRemove}
        variant="ghost"
        size="sm"
        className="absolute top-2 right-2"
        type="button"
      >
        <TrashIcon className="h-4 w-4" />
      </Button>
      {children}
    </div>
  );
};

import React from "react";
import { PlusIcon } from "lucide-react";
import { Button } from "@/components/ui/button";
import type { ArrayWrapperProps } from "@dual-autoform/react";

export const ArrayWrapper: React.FC<ArrayWrapperProps> = ({
  label,
  error,
  children,
  onAddItem,
  inputProps,
  parsedField,
}) => {
  const { key, ref, "aria-invalid": ariaInvalid, ...props } = inputProps;

  return (
    <div className="space-y-2">
      <div className="space-y-1">
        <h3
          className={`text-md font-medium focus:outline-none rounded-md px-2 py-1 transition-colors ${
            error
              ? "focus:border focus:border-destructive focus:ring-1 focus:ring-destructive/50"
              : ""
          }`}
          ref={ref}
          tabIndex={-1}
          aria-invalid={ariaInvalid}
          aria-describedby={`${key}-error ${key}-description`}
        >
          {label}
          {parsedField.required && <span className="text-destructive"> *</span>}
        </h3>
        {parsedField.fieldConfig?.description && (
          <div
            className="text-sm text-muted-foreground"
            id={key + "-description"}
          >
            {parsedField.fieldConfig.description}
          </div>
        )}
        {error && (
          <div className="text-sm text-destructive" id={key + "-error"}>
            {error}
          </div>
        )}
      </div>
      {children}
      <Button
        {...props}
        size="sm"
        type="button"
        variant="outline"
        onClick={(e) => {
          e.currentTarget.blur();
          onAddItem();
        }}
        aria-label={`add ${label}`}
      >
        <PlusIcon className="h-4 w-4" />
      </Button>
    </div>
  );
};

import React from "react";
