import React from "react";
import type { AutoFormFieldProps } from "@dual-autoform/react";
import { useFieldContext } from "@dual-autoform/react/tanstack-form";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";

export const BooleanField: React.FC<AutoFormFieldProps> = ({
  id,
  label,
  inputProps,
  parsedField,
}) => {
  const field = useFieldContext<boolean>();

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      e.preventDefault();
      (
        document.querySelector('button[type="submit"]') as HTMLButtonElement
      )?.click();
    }
  };

  return (
    <div className="flex items-center gap-2">
      <Checkbox
        id={id}
        name={field.name}
        {...inputProps}
        checked={!!field.state.value}
        onCheckedChange={(checked) => field.handleChange(!!checked)}
        onBlur={field.handleBlur}
        onKeyDown={handleKeyDown}
      />
      <Label htmlFor={id}>
        {label}
        {parsedField.required && <span className="text-destructive"> *</span>}
      </Label>
    </div>
  );
};

import React from "react";
import { CalendarIcon } from "lucide-react";

import { Calendar } from "@/components/ui/calendar";
import {
  InputGroup,
  InputGroupAddon,
  InputGroupButton,
  InputGroupInput,
} from "@/components/ui/input-group";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import type { AutoFormFieldProps } from "@dual-autoform/react";
import { useFieldContext } from "@dual-autoform/react/tanstack-form";

function formatDate(date: Date | undefined) {
  if (!date) return "";

  return date.toLocaleDateString("en-US", {
    day: "2-digit",
    month: "long",
    year: "numeric",
  });
}

function isValidDate(date: Date | undefined) {
  return !!date && !isNaN(date.getTime());
}

function toDate(value: unknown) {
  if (value instanceof Date) return isValidDate(value) ? value : undefined;
  if (typeof value === "string" && value) {
    const date = new Date(value);
    return isValidDate(date) ? date : undefined;
  }
  return undefined;
}

function toFieldValue(date: Date | undefined, currentValue: unknown) {
  if (!date) return "";
  return typeof currentValue === "string"
    ? date.toLocaleDateString("en-CA")
    : date;
}

export const DateField: React.FC<AutoFormFieldProps> = ({
  inputProps,
  error,
  id,
}) => {
  const field = useFieldContext<Date | string>();
  const selectedDate = toDate(field.state.value);
  const [open, setOpen] = React.useState(false);
  const [month, setMonth] = React.useState<Date | undefined>(selectedDate);
  const [inputValue, setInputValue] = React.useState(formatDate(selectedDate));

  React.useEffect(() => {
    setInputValue(formatDate(selectedDate));
    setMonth(selectedDate);
  }, [selectedDate?.getTime()]);

  return (
    <InputGroup>
      <InputGroupInput
        id={id}
        name={field.name}
        {...inputProps}
        aria-invalid={!!error || inputProps?.["aria-invalid"]}
        value={inputValue}
        placeholder={inputProps?.placeholder ?? "June 01, 2025"}
        onBlur={field.handleBlur}
        onChange={(e) => {
          const nextValue = e.target.value;
          const nextDate = new Date(nextValue);

          setInputValue(nextValue);

          if (isValidDate(nextDate)) {
            field.handleChange(toFieldValue(nextDate, field.state.value));
            setMonth(nextDate);
          } else if (!nextValue) {
            field.handleChange("");
          }
        }}
        onKeyDown={(e) => {
          inputProps?.onKeyDown?.(e);

          if (e.defaultPrevented) return;

          if (e.key === "ArrowDown") {
            e.preventDefault();
            setOpen(true);
          }
        }}
      />
      <InputGroupAddon align="inline-end">
        <Popover open={open} onOpenChange={setOpen}>
          <PopoverTrigger asChild>
            <InputGroupButton
              id={`${id}-date-picker`}
              variant="ghost"
              size="icon-xs"
              aria-label="Select date"
            >
              <CalendarIcon className="size-4" />
              <span className="sr-only">Select date</span>
            </InputGroupButton>
          </PopoverTrigger>
          <PopoverContent
            className="w-auto overflow-hidden p-0"
            align="end"
            alignOffset={-8}
            sideOffset={10}
          >
            <Calendar
              mode="single"
              selected={selectedDate}
              month={month}
              onMonthChange={setMonth}
              onSelect={(date) => {
                field.handleChange(toFieldValue(date, field.state.value));
                setInputValue(formatDate(date));
                setMonth(date);
                setOpen(false);
              }}
            />
          </PopoverContent>
        </Popover>
      </InputGroupAddon>
    </InputGroup>
  );
};

import { Input } from "@/components/ui/input";
import type { AutoFormFieldProps } from "@dual-autoform/react";
import { useFieldContext } from "@dual-autoform/react/tanstack-form";
import React from "react";

export const NumberField: React.FC<AutoFormFieldProps> = ({
  inputProps,
  error,
  id,
}) => {
  const field = useFieldContext<number>();

  return (
    <Input
      id={id}
      type="number"
      className={error ? "border-destructive" : ""}
      value={field.state.value ?? ""}
      onChange={(e) => field.handleChange(Number(e.target.value))}
      onBlur={field.handleBlur}
      name={field.name}
      {...inputProps}
    />
  );
};

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import type { AutoFormFieldProps } from "@dual-autoform/react";
import { useFieldContext } from "@dual-autoform/react/tanstack-form";
import React from "react";

export const SelectField: React.FC<AutoFormFieldProps> = ({
  inputProps,
  error,
  id,
  parsedField,
}) => {
  const field = useFieldContext<string>();
  const { ref, "aria-invalid": ariaInvalid, ...restInputProps } = inputProps as any;

  return (
    <Select
      onValueChange={(val) => field.handleChange(val)}
      value={field.state.value ?? ""}
      name={field.name}
      {...restInputProps}
    >
      <SelectTrigger
        id={id}
        ref={ref}
        aria-invalid={ariaInvalid}
        onBlur={field.handleBlur}
        className={error ? "border-destructive" : ""}
      >
        <SelectValue
          placeholder={inputProps?.placeholder ?? "Select an option"}
        />
      </SelectTrigger>
      <SelectContent>
        {(parsedField.options || []).map(([key, label], index) => (
          <SelectItem key={`${key}-${index}`} value={label}>
            {label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
};

